  ('optician-moex-02119', 'optician', 'optician-moex-107-d6d7f3e6', 'sub-optician-02', NULL, 'single_choice', '某近視眼患者其遠點為眼前10 cm ，且其調節力為10.00 D，在未配戴矯正鏡片時，患者的近點在眼前何 處？', '["眼前1 cm", "眼前2 cm", "眼前5 cm", "眼前10 cm"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:36+00:00", "source_pdf_sha1": "881ca37171e3", "answer_pdf_sha1": "f8c58b11cf7f", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "113", "s": "1109", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼鏡光學概要", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
